# Module providing base shape classes, interfaces, and structs

@abstract
class BaseShape:
    _name: str
    _id: int

    @static
    next_id: int = 1

    def __init__(self, name: str):
        self._name = name
        self._id = BaseShape.next_id
        BaseShape.next_id += 1

    @property
    def name(self) -> str:
        return self._name

    @property
    def id(self) -> int:
        return self._id

    @virtual
    def describe(self) -> str:
        return f"Shape: {self._name} (ID: {self._id})"

    @abstract
    def area(self) -> float:
        pass

    @abstract
    def perimeter(self) -> float:
        pass

struct Point2D:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to(self, other: Point2D) -> float:
        dx: float = self.x - other.x
        dy: float = self.y - other.y
        return (dx * dx + dy * dy) ** 0.5

struct Size:
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height

    @property
    def area(self) -> float:
        return self.width * self.height

