# Module defining color enums and color-related operations

enum Color:
    RED = 0
    GREEN = 1
    BLUE = 2
    YELLOW = 3
    PURPLE = 4
    BLACK = 5
    WHITE = 6

@abstract
class Colorizable:
    _color: Color

    def __init__(self, color: Color):
        self._color = color

    @virtual
    def get_color_name(self) -> str:
        return self._color.name

    @virtual
    def get_color_value(self) -> int:
        return self._color.value

def color_to_rgb(color: Color) -> tuple[int, int, int]:
    # Returns RGB tuple for the color
    if color == Color.RED:
        return (255, 0, 0)
    elif color == Color.GREEN:
        return (0, 255, 0)
    elif color == Color.BLUE:
        return (0, 0, 255)
    elif color == Color.YELLOW:
        return (255, 255, 0)
    elif color == Color.PURPLE:
        return (128, 0, 128)
    else:
        return (0, 0, 0)

def darken(color: Color) -> Color:
    # Returns a darker version of the color (maps to BLACK-ish)
    return Color.BLACK

