# Module with concrete shape implementations - cross-module inheritance

from shapes import BaseShape, Point2D, Size
from colors import Color, Colorizable

class Circle(BaseShape, Colorizable):
    center: Point2D
    radius: float

    def __init__(self, center: Point2D, radius: float, color: Color):
        BaseShape.__init__(self, "Circle")
        Colorizable.__init__(self, color)
        self.center = center
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def describe(self) -> str:
        base: str = BaseShape.describe(self)
        area_val: float = self.area()
        return f"{base}, radius={self.radius:.2f}, area={area_val:.1f}"

class Rectangle(BaseShape, Colorizable):
    position: Point2D
    size: Size

    def __init__(self, position: Point2D, size: Size, color: Color):
        BaseShape.__init__(self, "Rectangle")
        Colorizable.__init__(self, color)
        self.position = position
        self.size = size

    @override
    def area(self) -> float:
        return self.size.area

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.size.width + self.size.height)

    @override
    def describe(self) -> str:
        base: str = BaseShape.describe(self)
        w: float = self.size.width
        h: float = self.size.height
        area_val: float = self.area()
        return f"{base}, {w:.1f}x{h:.1f}, area={area_val:.1f}"

class ShapeFactory:
    @staticmethod
    def create_circle(x: float, y: float, radius: float, color: Color) -> Circle:
        center: Point2D = Point2D(x, y)
        return Circle(center, radius, color)

    @staticmethod
    def create_rectangle(x: float, y: float, width: float, height: float, color: Color) -> Rectangle:
        pos: Point2D = Point2D(x, y)
        size: Size = Size(width, height)
        return Rectangle(pos, size, color)
